-- Run this once as a superuser: it installs the two extensions these exercises
-- use and builds the table they measure.
CREATE EXTENSION IF NOT EXISTS dblink;
CREATE EXTENSION IF NOT EXISTS pgstattuple;

DROP TABLE IF EXISTS events, archive CASCADE;
CREATE TABLE events (
  id      INT PRIMARY KEY,
  user_id INT NOT NULL,
  body    TEXT NOT NULL,
  seen    BOOLEAN NOT NULL DEFAULT false
);
INSERT INTO events
SELECT g, g % 1000, repeat('x', 50), false
FROM generate_series(1, 50000) g;
CREATE INDEX ix_events_user ON events(user_id);
ANALYZE events;

